const query = items[0].json.query || '';
const match = query.match(/title:([^,]+),?\s*genre:([^,]+),?\s*mood:([^,]+)/i);
const title = match ? match[1].trim() : query;
const genre = match ? match[2].trim() : 'electronic';
const mood = match ? match[3].trim() : 'epic';
const bodyJson = JSON.stringify({ title, genre, mood, provider: 'mistral' });
return [{ json: { bodyJson, title, genre, mood } }];

const res = items[0].json;
const concept = res.concept || {};
const summary = `Concept genere avec succes!

Titre: ${res.metadata?.title || 'Untitled'}
Genre: ${res.metadata?.genre || 'electronic'}
Mood: ${res.metadata?.mood || 'epic'}

Hook: ${concept.hook || 'N/A'}

Suno Prompt: ${concept.suno_prompt || 'N/A'}

Leonardo Prompt: ${concept.leonardo_prompt || 'N/A'}

YouTube: ${concept.youtube_title || 'N/A'}
TikTok: ${concept.tiktok_caption || 'N/A'}
Instagram: ${concept.instagram_caption || 'N/A'}

Project ID: ${res.projectId || 'N/A'}`;
return [{ json: { response: summary, projectId: res.projectId, concept } }];
